using Microsoft.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

// Train the model before building the app so we can register the pool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
using (var loggerFactory = LoggerFactory.Create(b => b.AddConsole()))
{
    var logger = loggerFactory.CreateLogger<ModelTrainingService>();
    var trainer = new ModelTrainingService(logger, builder.Environment);
    trainer.TrainAndEvaluate();
}

// Register the pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

